package log

import (
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
)

func TestWindowsLineEndingsHook(t *testing.T) {
	tests := []struct {
		name     string
		input    string
		expected string
	}{
		{
			name:     "converts single LF to CRLF",
			input:    "Hello\nWorld",
			expected: "Hello\r\nWorld",
		},
		{
			name:     "preserves existing CRLF",
			input:    "Hello\r\nWorld",
			expected: "Hello\r\nWorld",
		},
		{
			name:     "converts multiple LF to CRLF",
			input:    "Line1\nLine2\nLine3",
			expected: "Line1\r\nLine2\r\nLine3",
		},
		{
			name:     "handles mixed CRLF and LF",
			input:    "Line1\r\nLine2\nLine3",
			expected: "Line1\r\nLine2\r\nLine3",
		},
		{
			name:     "no double conversion of CRLF",
			input:    "Hello\r\nWorld\nEnd",
			expected: "Hello\r\nWorld\r\nEnd",
		},
		{
			name:     "empty string",
			input:    "",
			expected: "",
		},
		{
			name:     "no newlines",
			input:    "Hello World",
			expected: "Hello World",
		},
		{
			name:     "trailing LF",
			input:    "Hello\n",
			expected: "Hello\r\n",
		},
		{
			name:     "trailing CRLF",
			input:    "Hello\r\n",
			expected: "Hello\r\n",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := normalizeLineEndings(tt.input)
			assert.Equal(t, tt.expected, result)
		})
	}
}

func TestWindowsLineEndingsHookWithEntry(t *testing.T) {
	hook := &WindowsLineEndingHook{}

	t.Run("converts message line endings", func(t *testing.T) {
		entry := &logrus.Entry{
			Message: "Hello\nWorld",
		}
		err := hook.Fire(entry)
		assert.Nil(t, err)
		assert.Equal(t, "Hello\r\nWorld", entry.Message)
	})

	t.Run("preserves CRLF in message", func(t *testing.T) {
		entry := &logrus.Entry{
			Message: "Hello\r\nWorld",
		}
		err := hook.Fire(entry)
		assert.Nil(t, err)
		assert.Equal(t, "Hello\r\nWorld", entry.Message)
	})

	t.Run("converts line endings in data fields", func(t *testing.T) {
		entry := &logrus.Entry{
			Message: "Error occurred",
			Data: logrus.Fields{
				"details": "Stack\ntrace\nhere",
			},
		}
		err := hook.Fire(entry)
		assert.Nil(t, err)
		assert.Equal(t, "Stack\r\ntrace\r\nhere", entry.Data["details"])
	})

	t.Run("handles multiple data fields", func(t *testing.T) {
		entry := &logrus.Entry{
			Message: "Error\noccurred",
			Data: logrus.Fields{
				"details": "First\nfield",
				"trace":   "Second\nfield",
			},
		}
		err := hook.Fire(entry)
		assert.Nil(t, err)
		assert.Equal(t, "Error\r\noccurred", entry.Message)
		assert.Equal(t, "First\r\nfield", entry.Data["details"])
		assert.Equal(t, "Second\r\nfield", entry.Data["trace"])
	})
}

package log

import (
	"fmt"
	"reflect"
	"runtime"
	"strings"

	"github.com/sirupsen/logrus"
)

// WindowsLineEndingHook is a logrus hook that normalizes line endings to CRLF on Windows
type WindowsLineEndingHook struct {
	// Only enabled on Windows
	enabled bool
}

// NewWindowsLineEndingHook creates a new WindowsLineEndingHook
func NewWindowsLineEndingHook() *WindowsLineEndingHook {
	return &WindowsLineEndingHook{
		enabled: runtime.GOOS == "windows",
	}
}

// Levels returns the log levels this hook applies to
func (h *WindowsLineEndingHook) Levels() []logrus.Level {
	return logrus.AllLevels
}

// Fire processes the log entry and normalizes line endings
func (h *WindowsLineEndingHook) Fire(e *logrus.Entry) error {
	if !h.enabled {
		return nil
	}

	// Process the message
	e.Message = normalizeLineEndings(e.Message)

	// Process data fields
	for k, v := range e.Data {
		switch val := v.(type) {
		case string:
			e.Data[k] = normalizeLineEndings(val)
		case fmt.Stringer:
			e.Data[k] = normalizeLineEndings(val.String())
		}
	}

	return nil
}

// normalizeLineEndings converts LF to CRLF, but preserves existing CRLF sequences
func normalizeLineEndings(s string) string {
	if s == "" {
		return s
	}

	var result strings.Builder
	result.Grow(len(s))

	for i := 0; i < len(s); i++ {
		c := s[i]

		if c == '\n' {
			// Check if this is part of an existing \r\n sequence
			if i > 0 && s[i-1] == '\r' {
				// This is already part of \r\n, just write the \n
				result.WriteByte(c)
			} else {
				// This is a standalone \n, convert to \r\n
				result.WriteString("\r\n")
			}
		} else {
			result.WriteByte(c)
		}
	}

	return result.String()
}

